// src/components/VehicleForm.js
import React, { useState } from "react";
import { createVehicle } from "../services/api";

export default function VehicleForm({ onCreated }) {
  const [licensePlate, setLicensePlate] = useState("");
  const [status, setStatus] = useState("active");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setLoading(true);
    try {
      // API expects snake_case
      await createVehicle({ license_plate: licensePlate, status });
      setLicensePlate("");
      setStatus("active");
      onCreated && onCreated();
    } catch (err) {
      if (err.response) {
        console.error("Create vehicle error:", err.response.status, err.response.data);
        setError(`Error ${err.response.status}`);
      } else if (err.request) {
        console.error("Create vehicle network error:", err.request);
        setError("Network error");
      } else {
        console.error("Create vehicle setup error:", err.message);
        setError("Client setup error");
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} style={{ display: "grid", gap: 10 }}>
      {error && <div style={{ color: "red" }}>{error}</div>}

      <input
        className="g-input"
        placeholder="KA-01-AB-1234"
        value={licensePlate}
        onChange={(e) => setLicensePlate(e.target.value)}
        required
      />

      <select
        className="g-input"
        value={status}
        onChange={(e) => setStatus(e.target.value)}
      >
        <option value="active">active</option>
        <option value="idle">idle</option>
        <option value="maintenance">maintenance</option>
      </select>

      <button className="g-btn" type="submit" disabled={loading}>
        {loading ? "Adding…" : "Add"}
      </button>
    </form>
  );
}
